import 'dart:math' as math;

class MinorUnits {
  static int parse(String text, {int scale = 2}) {
    if (scale < 0) throw ArgumentError.value(scale, 'scale');
    final factor = math.pow(10, scale).toDouble();
    return (double.parse(text) * factor).round();
  }
}

