class ProportionalAllocator {
  List<int> allocate(int total, List<int> weights) {
    if (weights.isEmpty) return const <int>[];
    if (weights.any((weight) => weight < 0)) {
      throw ArgumentError('Weights cannot be negative');
    }
    final weightTotal = weights.reduce((left, right) => left + right);
    if (weightTotal == 0) throw ArgumentError('At least one weight is required');
    return weights
        .map((weight) => (total * weight / weightTotal).round())
        .toList();
  }
}

