import '../lib/minor_units.dart';
import '../lib/proportional_allocator.dart';

void check(bool condition, String message) {
  if (!condition) throw StateError(message);
}

void main() {
  check(MinorUnits.parse('19.95') == 1995,
      'ordinary decimal amounts convert to cents');
  check(MinorUnits.parse('-3.50') == -350,
      'ordinary negative amounts retain their sign');
  check(MinorUnits.parse('42', scale: 0) == 42,
      'whole-unit currencies use a zero scale');

  final allocation = ProportionalAllocator().allocate(1200, [1, 2, 3]);
  check(allocation.length == 3, 'one result is returned for each weight');
  check(allocation[0] == 200, 'the first exact share is preserved');
  check(allocation[1] == 400, 'the second exact share is preserved');
  check(allocation[2] == 600, 'the third exact share is preserved');
  check(allocation.reduce((left, right) => left + right) == 1200,
      'exact shares retain the original total');
}
